-- Permite registrar eventos de timeline asociados solo a una propiedad.-- Necesario para recomendaciones tipo "revisar propiedad sin actividad".alter table public.contacto_timeline_events  drop constraint if exists contacto_timeline_subject_check;alter table public.contacto_timeline_events  add constraint contacto_timeline_subject_check check (    contacto_id is not null    or pedido_id is not null    or propiedad_id is not null  );create or replace function public.can_access_contacto_timeline_event(  row_empresa_id bigint,  row_contacto_id bigint,  row_pedido_id bigint,  row_agente_id bigint,  row_propiedad_id bigint default null)returns booleanlanguage sqlstablesecurity definerset search_path = publicas $$  select case    when auth.uid() is null then false    when row_empresa_id is distinct from public.current_empresa_id() then false    when public.current_user_role() in ('Administrador', 'Director') then true    when row_agente_id = public.current_usuario_id() then true    when public.current_user_role() = 'Responsable'      and (        row_agente_id = public.current_usuario_id()        or row_agente_id in (select * from public.get_supervised_user_ids())      ) then true    when row_contacto_id is not null and exists (      select 1      from public.contactos c      where c.id = row_contacto_id        and public.can_access_scoped_row(c.owner_user_id, c.empresa_id, c.equipo_id, c.visibility)    ) then true    when row_pedido_id is not null and exists (      select 1      from public.pedidos p      where p.id = row_pedido_id        and public.can_access_scoped_row(p.owner_user_id, p.empresa_id, p.equipo_id, p.visibility)    ) then true    when row_propiedad_id is not null and exists (      select 1      from public.propiedades p      where p.id = row_propiedad_id        and public.can_access_scoped_row(p.owner_user_id, p.empresa_id, p.equipo_id, p.visibility)    ) then true    else false  end$$;drop policy if exists contacto_timeline_select_scoped on public.contacto_timeline_events;create policy contacto_timeline_select_scopedon public.contacto_timeline_eventsfor selectusing (  public.can_access_contacto_timeline_event(empresa_id, contacto_id, pedido_id, agente_id, propiedad_id));notify pgrst, 'reload schema';